export interface Review {
  id: string;
  user: string;
  rating: number;
  comment: string;
  date: string;
}

export interface Drone {
  id: string;
  name: string;
  price: number;
  description: string;
  longDescription: string;
  image: string;
  gallery: string[];
  category: 'Recon' | 'Attack' | 'Logistics' | 'Consumer';
  specs: {
    range: string;
    battery: string;
    payload: string;
    topSpeed: string;
    signalType: string;
  };
  reviews: Review[];
}

export type ViewState = 'landing' | 'shop' | 'generator' | 'product-detail';

import React, { useState } from 'react';
import { DRONES } from '../constants';
import { Drone } from '../types';

interface ShopProps {
  onSelectDrone: (id: string) => void;
}

const Shop: React.FC<ShopProps> = ({ onSelectDrone }) => {
  const [filter, setFilter] = useState<string>('All');
  const categories = ['All', 'Attack', 'Recon', 'Logistics', 'Consumer'];

  const filteredDrones = filter === 'All' 
    ? DRONES 
    : DRONES.filter(d => d.category === filter);

  return (
    <div className="pt-24 pb-12 px-6 max-w-7xl mx-auto min-h-screen">
      <div className="flex flex-col md:flex-row md:items-end justify-between mb-12 gap-6">
        <div>
          <h2 className="text-4xl font-syncopate font-bold mb-2">ORDNANCE <span className="gold-text">SHOP</span></h2>
          <p className="text-gray-500 text-sm uppercase tracking-widest">Select your equipment for operational deployment</p>
        </div>

        <div className="flex flex-wrap gap-2">
          {categories.map(cat => (
            <button
              key={cat}
              onClick={() => setFilter(cat)}
              className={`px-4 py-1 text-[10px] font-bold uppercase tracking-widest border transition-all ${
                filter === cat ? 'gold-bg text-black border-none' : 'border-white/10 text-gray-400 hover:border-white/30'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
        {filteredDrones.map(drone => (
          <div 
            key={drone.id} 
            onClick={() => onSelectDrone(drone.id)}
            className="group bg-[#0a0a0a] border border-white/5 hover:border-white/20 transition-all duration-300 cursor-pointer"
          >
            <div className="relative overflow-hidden aspect-[4/5]">
              <img 
                src={drone.image} 
                alt={drone.name} 
                className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-500 group-hover:scale-110" 
              />
              <div className="absolute top-2 right-2 bg-black/80 px-2 py-1 border border-white/10">
                <span className="text-[10px] gold-text font-bold uppercase tracking-widest">{drone.category}</span>
              </div>
              <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-80" />
              <div className="absolute bottom-4 left-4 right-4">
                <button className="w-full bg-white/10 backdrop-blur-md border border-white/10 text-white py-2 text-xs font-bold uppercase tracking-widest hover:gold-bg hover:text-black hover:border-none transition-all duration-300">
                  Inspect Dossier
                </button>
              </div>
            </div>

            <div className="p-4">
              <div className="flex justify-between items-start mb-2">
                <h3 className="font-syncopate text-sm font-bold tracking-tight uppercase">{drone.name}</h3>
                <span className="text-xs gold-text font-mono">₹{drone.price.toLocaleString()}</span>
              </div>
              <p className="text-gray-500 text-xs line-clamp-2 mb-4 leading-relaxed">{drone.description}</p>

              <div className="grid grid-cols-3 gap-2 pt-4 border-t border-white/5">
                <div className="text-center">
                  <p className="text-[8px] text-gray-500 uppercase">Range</p>
                  <p className="text-[10px] font-bold">{drone.specs.range}</p>
                </div>
                <div className="text-center">
                  <p className="text-[8px] text-gray-500 uppercase">Battery</p>
                  <p className="text-[10px] font-bold">{drone.specs.battery}</p>
                </div>
                <div className="text-center">
                  <p className="text-[8px] text-gray-500 uppercase">Payload</p>
                  <p className="text-[10px] font-bold">{drone.specs.payload}</p>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Shop;

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import Shop from './components/Shop';
import AIGenerator from './components/AIGenerator';
import ProductDetail from './components/ProductDetail';
import Features from './components/Features';
import { ViewState } from './types';
import { DRONES } from './constants';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('landing');
  const [loading, setLoading] = useState(true);
  const [selectedDroneId, setSelectedDroneId] = useState<string | null>(null);

  useEffect(() => {
    // Initializing sequence simulation
    const timer = setTimeout(() => setLoading(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  const handleSelectDrone = (id: string) => {
    setSelectedDroneId(id);
    setView('product-detail');
    window.scrollTo(0, 0);
  };

  const selectedDrone = DRONES.find(d => d.id === selectedDroneId);

  if (loading) {
    return (
      <div className="min-h-screen bg-black flex flex-col items-center justify-center">
        <div className="w-48 h-[1px] bg-white/10 mb-8 relative overflow-hidden">
          <div className="absolute top-0 left-0 h-full gold-bg animate-[loading_2s_ease-in-out_infinite]" style={{ width: '40%' }} />
        </div>
        <div className="text-center">
          <p className="font-syncopate text-xl font-bold tracking-tighter mb-1">IND<span className="gold-text">-</span>DRONE</p>
          <p className="text-[8px] uppercase tracking-[0.5em] text-gray-500 animate-pulse">Initializing Interface Systems</p>
        </div>
        <style>{`
          @keyframes loading {
            0% { transform: translateX(-100%); }
            100% { transform: translateX(250%); }
          }
        `}</style>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#050505] selection:gold-bg selection:text-black">
      <Navbar currentView={view} onNavigate={setView} />

      <main className="transition-opacity duration-500">
        {view === 'landing' && (
          <>
            <Hero onStart={() => setView('shop')} />
            <Features />
          </>
        )}
        {view === 'shop' && <Shop onSelectDrone={handleSelectDrone} />}
        {view === 'generator' && <AIGenerator />}
        {view === 'product-detail' && selectedDrone && (
          <ProductDetail 
            drone={selectedDrone} 
            onBack={() => setView('shop')} 
          />
        )}
      </main>

      {/* Footer */}
      <footer className="border-t border-white/5 py-12 px-6 mt-24">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-8">
          <div>
            <div className="flex items-center space-x-2 mb-4">
              <div className="w-6 h-6 gold-bg rounded-sm flex items-center justify-center">
                <span className="text-black font-bold text-sm">I</span>
              </div>
              <span className="font-syncopate text-lg font-bold tracking-tighter">IND<span className="gold-text">-</span>DRONE</span>
            </div>
            <p className="text-gray-500 text-[10px] uppercase tracking-widest">MADE IN INDIA • FOR THE WORLD</p>
          </div>

          <div className="flex space-x-12">
            <div>
              <h5 className="text-[10px] font-bold uppercase tracking-widest mb-4">Tactical</h5>
              <ul className="text-gray-600 space-y-2 text-xs uppercase tracking-tighter">
                <li className="hover:text-white cursor-pointer transition-colors">Surveillance</li>
                <li className="hover:text-white cursor-pointer transition-colors">Strike Units</li>
                <li className="hover:text-white cursor-pointer transition-colors">Logistics</li>
              </ul>
            </div>
            <div>
              <h5 className="text-[10px] font-bold uppercase tracking-widest mb-4">Command</h5>
              <ul className="text-gray-600 space-y-2 text-xs uppercase tracking-tighter">
                <li className="hover:text-white cursor-pointer transition-colors">Support</li>
                <li className="hover:text-white cursor-pointer transition-colors">Careers</li>
                <li className="hover:text-white cursor-pointer transition-colors">Portal</li>
              </ul>
            </div>
          </div>
        </div>
        <div className="mt-12 text-center">
          <p className="text-[8px] text-gray-700 uppercase tracking-[0.2em]">© 2024 IND-DRONE AEROSPACE. ALL RIGHTS RESERVED. ENCRYPTED CONNECTION.</p>
        </div>
      </footer>

      {/* Persistent Scanline Effect Overlay */}
      <div className="fixed inset-0 pointer-events-none z-[60] opacity-[0.03] bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] bg-[length:100%_2px,3px_100%]" />
    </div>
  );
};

export default App;
